            sh.append({"idx":i,"price":h,"dt":candles[i]["datetime"]})
        if all(candles[i-j]["low"]>l for j in range(1,n+1)) and all(candles[i+j]["low"]>l for j in range(1,n+1)):
            sl.append({"idx":i,"price":l,"dt":candles[i]["datetime"]})
